Tests for JSON Config Merger Utility

Tests cover:
1. Basic shallow merge (two flat dicts)
2. Deep nested merge (3 levels)
3. List concatenation
4. Override precedence (3 configs, last wins)
5. Type conflict detection
6. Empty input handling
"""

import sys
sys.path.insert(0, '/Applications/AITerminalTools/tmp')

from eval36_merger import merge_configs, validate_merge


def test_basic_shallow_merge():
    """Test merging two flat dictionaries"""
    config1 = {
        'name': 'Service A',
        'port': 8080,
        'enabled': True
    }
    config2 = {
        'name': 'Service B',  # Override
        'timeout': 30,
        'enabled': False      # Override
    }

    result = merge_configs(config1, config2)

    assert result['name'] == 'Service B', f"Expected 'Service B', got {result['name']}"
    assert result['port'] == 8080, f"Expected 8080, got {result['port']}"
    assert result['timeout'] == 30, f"Expected 30, got {result['timeout']}"
    assert result['enabled'] == False, f"Expected False, got {result['enabled']}"
    print("✓ test_basic_shallow_merge passed")


def test_deep_nested_merge():
    """Test merging with 3 levels of nesting"""
    config1 = {
        'database': {
            'host': 'localhost',
            'port': 5432,
            'credentials': {
                'username': 'admin',
                'password': 'secret'
            }
        }
    }

    config2 = {
        'database': {
            'port': 5433,  # Override
            'credentials': {
                'username': 'admin',  # Keep
                'token': 'abc123'     # Add
            },
            'ssl': True
        }
    }

    result = merge_configs(config1, config2)

    assert result['database']['host'] == 'localhost'
    assert result['database']['port'] == 5433
    assert result['database']['credentials']['username'] == 'admin'
    assert result['database']['credentials']['password'] == 'secret'
    assert result['database']['credentials']['token'] == 'abc123'
    assert result['database']['ssl'] == True
    print("✓ test_deep_nested_merge passed")


def test_list_concatenation():
    """Test that lists are concatenated (later appends to earlier)"""
    config1 = {
        'paths': ['/usr/bin', '/usr/local/bin'],
        'plugins': ['plugin-a']
    }

    config2 = {
        'paths': ['/opt/bin'],  # Different list
        'plugins': ['plugin-b', 'plugin-c']
    }

    result = merge_configs(config1, config2)

    assert result['paths'] == ['/usr/bin', '/usr/local/bin', '/opt/bin']
    assert result['plugins'] == ['plugin-a', 'plugin-b', 'plugin-c']
    print("✓ test_list_concatenation passed")


def test_override_precedence():
    """Test that later configs override earlier ones"""
    config1 = {
        'api': {
            'version': '1.0',
            'endpoint': 'v1/'
        }
    }

    config2 = {
        'api': {
            'version': '2.0'  # Override
        }
    }

    config3 = {
        'api': {
            'endpoint': 'v2/'  # Override
        }
    }

    result = merge_configs(config1, config2, config3)

    assert result['api']['version'] == '2.0', "config2 should override version"
    assert result['api']['endpoint'] == 'v2/', "config3 should override endpoint"
    print("✓ test_override_precedence passed")


def test_type_conflict_detection():
    """Test detection of type conflicts across configs"""
    config1 = {
        'name': 'Service A',
        'config': {'key': 'value'}
    }

    config2 = {
        'name': 'Service B',  # Same type (string), no conflict
        'config': 123  # Different type (int) - should detect conflict
    }

    conflicts = validate_merge(config1, config2)

    assert len(conflicts) == 1, f"Expected 1 conflict, got {len(conflicts)}"
    assert 'config' in conflicts[0], f"Expected 'config' in conflicts, got {conflicts}"
    assert 'conflicting types' in conflicts[0], f"Expected 'conflicting types' in {conflicts[0]}"
    print("✓ test_type_conflict_detection passed")


def test_empty_input_handling():
    """Test handling of empty input"""
    # No configs
    result = merge_configs()
    assert result == {}, f"Expected empty dict, got {result}"

    # Single config
    config = {'a': 1, 'b': 2}
    result = merge_configs(config)
    assert result == config, f"Expected same config, got {result}"

    # Empty dicts
    result = merge_configs({}, {})
    assert result == {}, f"Expected empty dict, got {result}"

    print("✓ test_empty_input_handling passed")


def run_all_tests():
    """Run all tests and report results"""
    tests = [
        test_basic_shallow_merge,
        test_deep_nested_merge,
        test_list_concatenation,
        test_override_precedence,
        test_type_conflict_detection,
        test_empty_input_handling
    ]

    print("Running tests for eval36_merger...")
    print("=" * 60)

    passed = 0
    failed = 0

    for test in tests:
        try:
            test()
            passed += 1
        except AssertionError as e:
            failed += 1
            print(f"✗ {test.__name__} failed: {e}")
        except Exception as e:
            failed += 1
            print(f"✗ {test.__name__} error: {e}")

    print("=" * 60)
    print(f"Results: {passed} passed, {failed} failed")

    return failed == 0


if __name__ == '__main__':
    success = run_all_tests()
    sys.exit(0 if success else 1)
